const menu=document.querySelector('[data-mobile-menu]');const opener=document.querySelector('[data-menu-open]');const closer=document.querySelector('[data-menu-close]');const theme=document.querySelector('[data-theme-toggle]');let previous=null;function hideMenu(){if(menu.open)menu.close();opener?.setAttribute('aria-expanded','false');previous?.focus()}opener?.addEventListener('click',()=>{previous=document.activeElement;menu.showModal();opener.setAttribute('aria-expanded','true');closer.focus()});closer?.addEventListener('click',hideMenu);menu?.addEventListener('click',event=>{if(event.target===menu)hideMenu()});menu?.addEventListener('cancel',event=>{event.preventDefault();hideMenu()});document.querySelectorAll('.mobile-menu a').forEach(link=>link.addEventListener('click',hideMenu));theme?.addEventListener('click',()=>{const dark=document.documentElement.dataset.theme==='dark';document.documentElement.dataset.theme=dark?'light':'dark';theme.textContent=dark?'Tema':'Ljust';theme.setAttribute('aria-label',dark?'Byt till mörkt tema':'Byt till ljust tema')});document.querySelector('[data-search]')?.addEventListener('submit',event=>{event.preventDefault();const query=event.currentTarget.querySelector('input').value.trim();event.currentTarget.querySelector('[data-search-result]').textContent=query?`Sökningen efter "${query}" är förberedd för sökytan i prototypen.`:''});
